CREATE OR REPLACE FUNCTION graphql_public.graphql("operationName" text DEFAULT NULL::text, query text DEFAULT NULL::text, variables jsonb DEFAULT NULL::jsonb, extensions jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
            DECLARE
                server_version float;
            BEGIN
                server_version = (SELECT (SPLIT_PART((select version()), ' ', 2))::float);

                IF server_version >= 14 THEN
                    RETURN jsonb_build_object(
                        'errors', jsonb_build_array(
                            jsonb_build_object(
                                'message', 'pg_graphql extension is not enabled.'
                            )
                        )
                    );
                ELSE
                    RETURN jsonb_build_object(
                        'errors', jsonb_build_array(
                            jsonb_build_object(
                                'message', 'pg_graphql is only available on projects running Postgres 14 onwards.'
                            )
                        )
                    );
                END IF;
            END;
        $function$

CREATE OR REPLACE FUNCTION public.confirm_rating_match_score(p_match_id uuid, p_confirmed_by uuid, p_rating_changes jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_match public.matches%rowtype;
  v_submitter_team int;
  v_confirmer_team int;
  v_player_id text;
  v_change jsonb;
begin
  if auth.uid() is null or auth.uid() <> p_confirmed_by then
    raise exception 'invalid confirmer' using errcode = '42501';
  end if;

  select * into v_match
  from public.matches
  where id = p_match_id
  for update;

  if not found or v_match.is_rating_match is not true then
    raise exception 'rated pending match not found';
  end if;

  if v_match.score_status <> 'pending_confirmation' then
    raise exception 'score is not pending confirmation';
  end if;

  select case
    when exists (
      select 1 from jsonb_array_elements(coalesce(v_match.team1, '[]'::jsonb)) p
      where p->>'id' = v_match.score_submitted_by::text
    ) then 1
    when exists (
      select 1 from jsonb_array_elements(coalesce(v_match.team2, '[]'::jsonb)) p
      where p->>'id' = v_match.score_submitted_by::text
    ) then 2
  end into v_submitter_team;

  select case
    when exists (
      select 1 from jsonb_array_elements(coalesce(v_match.team1, '[]'::jsonb)) p
      where p->>'id' = p_confirmed_by::text
    ) then 1
    when exists (
      select 1 from jsonb_array_elements(coalesce(v_match.team2, '[]'::jsonb)) p
      where p->>'id' = p_confirmed_by::text
    ) then 2
  end into v_confirmer_team;

  if v_submitter_team is null or v_confirmer_team is null or v_submitter_team = v_confirmer_team then
    raise exception 'confirmation must come from opposite team' using errcode = '42501';
  end if;

  for v_player_id, v_change in
    select key, value from jsonb_each(p_rating_changes)
  loop
    update public.profiles
    set rating = (v_change->>'after')::numeric
    where id::text = v_player_id;
  end loop;

  update public.matches
  set status = 'completed',
      score_status = 'confirmed',
      score_confirmed_by = p_confirmed_by,
      "completedAt" = now(),
      "ratingChanges" = p_rating_changes
  where id = p_match_id;
end;
$function$

CREATE OR REPLACE FUNCTION public.rls_auto_enable()
 RETURNS event_trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'pg_catalog'
AS $function$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION public.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.updated_at = now();
  return new;
end;
$function$
